+    let plan = ContentionPlan::new()
+        .turn(SimulationActor::ForegroundSearch, "serve_query")
+        .turn(SimulationActor::SemanticAcquire, "verify_checksum")
+        .turn(SimulationActor::LexicalRepair, "resume_repair");
